INSERT INTO "hyundai-ventas"."agnMemory" VALUES ('5493874732132', '', 'Desarrollada', 'Staria', '', NULL, 'El cliente preguntó por la Staria Ultimate 4WD, se le mostraron imágenes principal e interior. Luego pidió ver todo el catálogo disponible y se le envió la imagen general con todos los modelos (HB20, HB20S, Creta, Tucson, Santa Fe, Staria), ofreciendo el link del catálogo web. Se le preguntó el uso previsto para orientar la elección.', '2026-07-16T14:57:08.33376+00:00', '2026-07-17T19:10:56.376715+00:00', '', '', '', '', '', '', 'https://agnhyundai.com.ar/wp-content/uploads/2025/07/destacados_garantia.jpg:principal, https://agnhyundai.com.ar/wp-content/uploads/2025/07/destacados_garantia.jpg:interior, https://agnhyundai.com.ar/wp-content/uploads/2026/07/Nuestros-Vehiculos.png:catalogo', 'Ultimate 4WD', '', '', '', 'false', '', '');
INSERT INTO "hyundai-ventas"."agnMemory" VALUES ('5493815505510', 'Oscar', 'Cierre', 'Creta', 'USD 15000 de entrega + financiación', NULL, 'Oscar reaccionó con entusiasmo a la imagen del interior del Creta (''hermoso!''). Sigue confirmada la llamada del sábado 12hs para avanzar. Datos registrados: USD 15000 de entrega + financiación, Santiago del Estero Capital, zona Norte, atención por llamada, uso particular, forma de pago financiado. Pendiente confirmar si elige la versión Safety +.', '2026-07-17T15:22:13.802365+00:00', '2026-07-17T18:36:35.7613+00:00', 'oscar.greco@gmail.com', '', 'Santiago del Estero', 'Capital', 'Norte', '', 'https://agnhyundai.com.ar/wp-content/uploads/2025/06/3.jpg:principal,https://agnhyundai.com.ar/wp-content/uploads/2025/06/creta25-destacados-espacio-interior-1.jpg:interior', '', 'Particular', 'Financiado', 'Sábado 12hs', 'false', '', '');
INSERT INTO "hyundai-ventas"."agnMemory" VALUES ('5493815635227', 'Gustavo', 'Cierre', 'Tucson', '', NULL, 'Gustavo, de Salta, busca un auto familiar para 5 personas. Eligió antes Creta Safety+ y luego Tucson 1.6 T-GDI Híbrido 4WD HEV, de la cual recibió imagen principal. Se ofreció visita presencial con test drive en sucursal Pellegrini 1030, pidió tiempo para pensarlo. Preguntó ubicación, café en sucursal, precio (derivado a asesor), catálogo, contacto y nombre de Geni. Pidió ver otra versión de Tucson: 2.0 Smartstream Nafta 2WD AT, se le envió imagen principal. Preguntó diferencia entre Híbrida 4WD HEV y Nafta 4WD DCT, se explicó diferencia general. Ahora preguntó qué modelos vende AGN, se le listaron HB20, HB20S, Creta, Tucson y STARIA. Faltan ciudad puntual, presupuesto y forma de pago.', '2026-07-17T12:18:16.999435+00:00', '2026-07-17T15:55:02.67443+00:00', '', '', 'Salta', '', 'Salta', '', 'https://agnhyundai.com.ar/wp-content/uploads/2025/06/3.jpg:principal,https://agnhyundai.com.ar/wp-content/uploads/2025/06/creta25-destacados-espacio-interior-1.jpg:interior,https://agnhyundai.com.ar/wp-content/uploads/2025/06/creta25-destacados-espacioso-y-moderno.jpg:exterior_lateral,https://agnhyundai.com.ar/wp-content/uploads/2025/07/Hyundai-tucson-destacados-botton-cta-disenio.jpg:principal,https://agnhyundai.com.ar/wp-content/uploads/2025/06/Hyundai-tucson-destacados-botton-cta-disenio.jpg:principal', '2.0 Smartstream Nafta 2WD AT', 'Particular', '', '', 'true', 'lunes 9:30hs (propuesta, pendiente confirmación)', '');
INSERT INTO "hyundai-ventas"."agnMemory" VALUES ('5493815760221', 'Juan', 'Abierta', '', '', NULL, 'El cliente se llama Juan y brindó su nombre de pila. Todavía no compartió apellido, modelo de interés, presupuesto ni provincia. Se le preguntará por el uso previsto para orientar la conversación.', '2026-07-17T17:25:39.768324+00:00', '2026-07-17T20:28:32.517016+00:00', '', '', '', '', '', '', '', '', '', '', '', 'false', '', '');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('a66037b3-47a0-4582-9c32-f533289b1bc5', 'e31bb0d2-7f4d-4caa-b2a9-becf42a8fde0', 'Hyundai', 'argumento_venta', 'HB20 — seguridad como diferencial', 'Las 3 versiones incluyen 6 airbags de serie. La versión Platinum Safety suma el paquete ADAS completo: frenado autónomo de emergencia, asistente de mantenimiento de carril y alerta de tráfico cruzado trasero — un argumento fuerte para compradores con foco en seguridad familiar.', NULL, NULL, 'https://agnhyundai.com.ar/hb20/', NULL, NULL, 'true', '2026-07-13T14:43:56.710875+00:00', '2026-07-13T14:43:56.710875+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('c6164bb5-c92f-4b50-ad11-61addfdd3bc6', 'bfdb2324-4193-4288-9520-960c3f9d5a09', 'Hyundai', 'descripcion_modelo', 'HB20 — enfoque general', 'El HB20 se posiciona como un compacto con diseño renovado, parrilla frontal en negro brillante y luces traseras integradas. Apunta a un perfil de comprador que busca sensación deportiva y tecnología, sin resignar espacio interior ni seguridad.', '[0.011520386,0.00541687,-0.008682251,0.008529663,-0.015975952,0.005367279,-0.018615723,0.07879639,0.05154419,-0.017181396,-0.028900146,-0.009124756,-0.019012451,-0.05029297,0.06976318,0.00018894672,-0.01777649,-0.03286743,0.014419556,0.015197754,0.015022278,0.02760315,-0.0031051636,-0.006526947,0.0029945374,0.01473999,-0.026794434,-0.021362305,0.007888794,-0.015655518,-0.019256592,-0.038238525,0.0736084,-0.075683594,0.029312134,-0.0104904175,0.034301758,0.040008545,0.0690918,0.025543213,0.024917603,0.036956787,0.047302246,-0.012397766,0.036834717,-0.012763977,0.026687622,-0.049102783,0.027175903,0.011634827,-0.022323608,-0.015823364,0.008476257,0.086242676,-0.026443481,0.02192688,-0.018234253,0.020248413,0.030532837,0.031234741,0.03466797,-0.041870117,0.020080566,0.06124878,-0.007499695,-0.0345459,-0.0011920929,0.007335663,-0.017227173,-0.026824951,-0.007369995,0.05227661,-0.034851074,-0.016204834,-0.021896362,-0.005065918,-0.0064926147,-0.0793457,-0.01348114,0.018692017,-0.067993164,-0.02407837,-0.021392822,0.012214661,-0.025375366,0.01902771,0.009918213,-0.0022525787,-0.032073975,-0.026443481,-0.008911133,0.018371582,-0.013420105,-0.017547607,0.003168106,-0.0024318695,-0.0029640198,-0.031677246,0.0030231476,0.03189087,0.03955078,-0.023834229,-0.0009765625,-0.04562378,0.012565613,-0.035064697,-0.01386261,-0.017913818,-0.0127334595,0.08331299,0.05529785,-0.024368286,0.02784729,0.03756714,-0.038970947,-0.00945282,0.02053833,-0.033599854,-0.011482239,-0.010391235,-0.0046157837,-0.048339844,-0.024963379,-0.021347046,-0.032043457,-0.0