INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('1216', '325', '11912', '191', 'contactado_sin_respuesta', 'conversacion_iniciada', 'mensaje_whatsapp', 'whatsapp', 'Cliente solicitó revisar aumento de cuota y advirtió que no pagará si mantiene el monto. Se presentaron opciones de derivación, elevación interna o cupón.', 'informacion_recabada', '{"email": "servisfam@hotmail.com", "tipo_plan": "evaluacion", "observaciones": "Cliente reclama aumento de cuota (aprox. $400.000 → $850.986,28). Se ofreció derivación a Administración, elevación interna para revisión o tramitación de cupón para adelantar cuotas.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', 'evasivo', '2026-07-10T15:59:21.853801+00:00');
INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('1225', '854', '12014', '150', 'cerrado_exitoso', 'cupon_solicitado', 'mensaje_whatsapp', 'whatsapp', 'Usuario confirmó que prefiere pagar ahora. Se detallaron 3 opciones (Pago Fácil, Homebanking, consultar con Banco Macro). Esperando confirmación del método elegido.', 'adelanto_cuota_solicitado', '{"email": "licmalvarez04@gmail.com", "tipo_plan": "Cuota mensual", "observaciones": "Cliente prefirió pagar ahora; se explicaron opciones de pago y tiempos (cupón llega 24-48 hs). A la espera de elección de método.", "fecha_compromiso": "2026-07-13", "cuotas_comprometidas": 1}', 'colaborativo', '2026-07-13T14:42:27.927219+00:00');
