INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('385', '105', '11663', '105', ' contactado_sin_respuesta ', ' sin_deuda ', ' mensaje_whatsapp ', ' whatsapp ', ' Cliente confirmó que el correo era para el plan de Luis Facundo Echazu (Grupo 11663 - Orden 105). Plan figura al día. Oferta de adelantar cuotas realizada; pendiente confirmación de cantidad. ', ' sin_deuda_registrada ', '{"email": "accesoriospesadosagsa@gmail.com", "tipo_plan": "adelanto", "observaciones": "Cliente informó que el email de cobranza era para este plan. Info_status indica plan UP_TO_DATE. Se ofreció gestionar cupón para adelantar cuotas.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' neutral ', '2026-06-16T19:01:45.381164+00:00');
INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('386', '105', '11663', '105', ' contactado_sin_respuesta ', ' conversacion_iniciada ', ' mensaje_whatsapp ', ' whatsapp ', ' Ahorrista reportó aviso por mail. Oferta de verificación del correo o gestión de cupón para adelantar cuotas. Pendiente detalle del asunto/remitente o confirmación de cantidad de cuotas. ', ' informacion_recabada ', '{"email": "accesoriospesadosagsa@gmail.com", "tipo_plan": "evaluacion", "observaciones": "Ahorrista indicó recepción de aviso por mail. Plan figura al día en info_status. Se solicitó asunto/remitente para verificar o confirmar si desea adelantar cuotas.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' neutral ', '2026-06-16T19:43:47.93477+00:00');
